    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        int[] positions = new int[n];
        for (int i = 0; i < n; i++) {
            positions[i] = order[i];
        }

        // We need to find the minimum t such that the number of valid substrings is >= k
        // We'll use binary search on t (from 0 to n-1)
        long left = 0, right = n - 1;
        long answer = -1;

        while (left <= right) {
            long mid = (left + right) / 2;
            Set<Integer> stars = new HashSet<>();
            for (int i = 0; i <= mid; i++) {
                stars.add(positions[i]);
            }

            // Calculate the number of valid substrings
            int count = 0;
            for (int i = 0; i < n; i++) {
                if (stars.contains(i)) {
                    // The number of substrings that include this star
                    // is (i + 1) * (n - i)
                    count += (i + 1) * (n - i);
