        int n = s.length();
        int[] positions = new int[n];
        for (int i = 0; i < n; i++) {
            positions[i] = order[i];
        }

        // Store the positions of '*' in a list
        List<Integer> stars = new ArrayList<>();

        // Precompute the number of valid substrings after each step
        long[] validCounts = new long[n];
        for (int t = 0; t < n; t++) {
            int pos = positions[t];
            stars.add(pos);

            // Calculate the number of valid substrings that include the current star
            int left = 0;
            int right = 0;
            while (left < pos) {
                left++;
                if (left < pos) {
                    right = pos - left;
                }
            }
            while (right < pos) {
                right++;
                if (right > pos) {
                    left = pos - right;
                }
            }

            // Calculate the number of valid substrings that include the current star
            int leftCount = 0;
            int rightCount = 0;
            for (int i = 0; i < stars.size(); i++) {
                int star = stars.get(i);
                if (star < pos) {
                    leftCount++;
                } else {
                    rightCount++;
                }
            }

            // Total valid substrings after this step
            validCounts[t] = leftCount + rightCount;
        }

        // Find the earliest time t where validCounts[t] >= k
        for (int t = 0; t < n; t++) {
            if (validCounts[t] >= k) {
                return t;
            }
        }

        return -1;
    }
