import java.util.*;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        boolean[] replaced = new boolean[n];
        long[] prefix = new long[n + 1];

        // Precompute the number of '*' in the first i characters
        for (int i = 0; i < n; i++) {
            prefix[i + 1] = prefix[i] + (s.charAt(i) == '*' ? 1 : 0);
        }

        // For each position in order, simulate replacing the character and compute the number of valid substrings
        for (int t = 0; t < n; t++) {
            int pos = (int) order[t];
            if (replaced[pos]) continue; // Skip if already replaced

            replaced[pos] = true;
            // Compute the number of valid substrings after this replacement
            long count = 0;

            // For each possible start index
            for (int i = 0; i < n; i++) {
                // Find the first occurrence of '*' >= i
                int firstStar = -1;
                for (int j = i; j < n; j++) {
                    if (replaced[j]) {
                        firstStar = j;
                        break;
                    }
                }

                if (firstStar == -1) continue; // No '*' in this substring

                // Find the last occurrence of '*' <= n-1
                int lastStar = -1;
                for (int j = n - 1; j >= i; j--) {
                    if (replaced[j]) {
                        lastStar = j;
                        break;
                    }
                }

                if (lastStar == -1) continue; // No '*' in this substring

                // Number of valid substrings that include at least one '*'
                // = total substrings from i to lastStar - total substrings from i to firstStar - 1
                long totalSubstrings = (lastStar - i + 1) * (lastStar - i + 2) / 2;
                long substringsWithoutStar = (firstStar - i) * (firstStar - i + 1) / 2;
                count += totalSubstrings - substringsWithoutStar;
            }

            if (count >= k) {
                return t;
            }
        }

        return -1;
    }
}
